const items = $input.all();

function stripHtml(html) {
  if (!html) return "";
  return html
    .replace(/<[^>]*>/g, " ")        // remove all HTML tags
    .replace(/&amp;/g, "&")           // decode common HTML entities
    .replace(/&lt;/g, "<")
    .replace(/&gt;/g, ">")
    .replace(/&nbsp;/g, " ")
    .replace(/&rsquo;/g, "'")
    .replace(/&lsquo;/g, "'")
    .replace(/&rdquo;/g, '"')
    .replace(/&ldquo;/g, '"')
    .replace(/&mdash;/g, "—")
    .replace(/&ndash;/g, "–")
    .replace(/&hellip;/g, "...")
    .replace(/&reg;/g, "®")
    .replace(/&trade;/g, "™")
    .replace(/&euro;/g, "€")
    .replace(/\s+/g, " ")             // collapse multiple spaces/newlines
    .trim();
}

return items.map(item => {
  const rawTrailerUid = item.json.trailer_uid || "";
  const cleanTrailerUid = rawTrailerUid.split("?")[0];
  return {
    json: {
      ...item.json,
      trailer_uid: cleanTrailerUid,
      description: stripHtml(item.json.description),
      table_source: "catalogue_product_sources",
    }
  };
});

const items = $input.all();
const TARGET_CHANNEL_ID = "UCNaXVVdiW4ksPAtFKv8SdrA";

return items.map(item => {
  const video = item.json;
  const channelId = video.snippet?.channelId;
  const isKeymailer = channelId === TARGET_CHANNEL_ID;

  if (isKeymailer) {
    return {
      json: {
        yt_trailer_uid: video.id,
        hasYoutubeTrailerOnKM: true
      }
    };
  } else {
    return {
      json: {
        yt_trailer_uid: video.id,
        yt_title: video.snippet?.title,
        hasYoutubeTrailerOnKM: false
      }
    };
  }
});

