const existingProductIds = new Set(
  !isEmptyResult
    ? previousData
        .map(item => item.json.product_id)
        .filter(id => id !== undefined && id !== null)
    : []
);

// Add hasExist field to each item
const result = falseMatchData.map(item => {
  const productId = item.json.product_id;
  const hasExist = existingProductIds.has(productId);

  return {
    json: {
      ...item.json,
      hasExist
    }
  };
});

return result;
